from typing import List

def solve(prices: List[int], strategy: List[int], k: int) -> int:
    n = len(prices)
    max_profit = 0

    # Calculate the original profit
    original_profit = 0
    for i in range(n):
        original_profit += strategy[i] * prices[i]
    max_profit = original_profit

    # Try to modify each possible k-length subarray
    for i in range(n - k + 1):
        modified_profit = 0
        for j in range(n):
            if i <= j < i + k:
                # For the modified part, the first k/2 elements are 0 (hold), the rest are 1 (sell)
                if j < i + k // 2:
                    modified_profit += 0 * prices[j]
                else:
                    modified_profit += 1 * prices[j]
            else:
                modified_profit += strategy[j] * prices[j]
        max_profit = max(max_profit, modified_profit)

    return max_profit
